// ============================
// effects.js（演出エフェクト管理）
// ============================
// このファイルはゲーム中の視覚エフェクトを担当する。
// ・画面フラッシュ
// ・ビーム発射（CSSアニメ）
// ・気弾の光エフェクト
// ============================


// ------------------------------------------------------------
// 画面フラッシュ（白く光る）
// ------------------------------------------------------------
// body に .flash を付けて CSS アニメを発動させる。
// ------------------------------------------------------------
export function flashScreen() {
  document.body.classList.add("flash");

  // 300ms 後に消す（CSS と合わせて調整）
  setTimeout(() => {
    document.body.classList.remove("flash");
  }, 300);
}


// ------------------------------------------------------------
// ビーム発射エフェクト
// ------------------------------------------------------------
// #beam 要素に .beam-fire を付けて CSS アニメを発動。
// ------------------------------------------------------------
export function fireBeamEffect() {
  const beam = document.getElementById("beam");
  if (!beam) return;

  // 発射アニメ開始
  beam.classList.add("beam-fire");

  // 500ms 後にアニメ終了
  setTimeout(() => {
    beam.classList.remove("beam-fire");
  }, 500);
}


// ------------------------------------------------------------
// 気弾の光エフェクト（脈動）
// ------------------------------------------------------------
// 気弾が MAX のときに pulse を付ける。
// game.js 側で呼ばれる。
// ------------------------------------------------------------
export function pulseKiBall() {
  const ball = document.getElementById("ki-ball");
  if (!ball) return;

  ball.classList.add("pulse");

  // 600ms で一旦消す（連続で呼ばれても破綻しない）
  setTimeout(() => {
    ball.classList.remove("pulse");
  }, 600);
}
